    41→export const usePhysicalCards = () =>
    42→  useSelector(({ productsReducer }: { productsReducer: ProductsReducerProps }) =>
    43→    productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual).length >= 2
    44→      ? productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual).sort((a, b) => {
    45→          const dateA = moment(a.DataAberturaCartao, 'YYYY-MM-DD');
