import { AccountTypes, CustomerTypes } from '@semparar/mf-app-user';
import moment from 'moment';
import { useSelector } from 'react-redux';

import { ProductsReducerProps } from '../redux/ducks/customers/products';
import { AppReducers } from '../redux/reducers/Models';
import { getIsCanceledCard } from '../utils/getIsCanceledCard';

export const getAcountNumberInProducts = ({
  productsReducer,
}: {
  productsReducer: ProductsReducerProps;
}): string | undefined => productsReducer.data?.[0]?.Conta;

export const getDocumentNumber = ({
  customerReducer,
}: {
  customerReducer: typeof CustomerTypes;
}): string | undefined | null => customerReducer.document;

export const getDocumentCPF = ({
  customerReducer,
}: {
  customerReducer: typeof CustomerTypes;
}): string | undefined | null => customerReducer.username;

export const getCustomerCard = ({
  customerReducer,
}: {
  customerReducer: typeof CustomerTypes & {
    account: { card: { cardNumber: string } };
  };
}): string | undefined | null => customerReducer?.account?.card?.cardNumber;

export const getAcountNumber = ({
  accountReducer,
}: {
  accountReducer: typeof AccountTypes;
}): string | undefined | null => accountReducer.card?.account;

export const usePhysicalCards = () =>
  useSelector(({ productsReducer }: { productsReducer: ProductsReducerProps }) =>
    productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual).length >= 2
      ? productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual).sort((a, b) => {
          const dateA = moment(a.DataAberturaCartao, 'YYYY-MM-DD');
          const dateB = moment(b.DataAberturaCartao, 'YYYY-MM-DD');
          return dateB.diff(dateA);
        })
      : [productsReducer?.data?.[0]?.Cartoes?.find((card) => !card.Virtual)]
  );

export const getHolderPhysicalCards = ({
  productsReducer,
}: {
  productsReducer: ProductsReducerProps;
}) =>
  productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual && card.Titular).length >= 2
    ? productsReducer?.data?.[0]?.Cartoes?.filter((card) => !card.Virtual && card.Titular).sort(
        (a, b) => {
          const dateA = moment(a.DataAberturaCartao, 'YYYY-MM-DD');
          const dateB = moment(b.DataAberturaCartao, 'YYYY-MM-DD');
          return dateB.diff(dateA);
        }
      )
    : [productsReducer?.data?.[0]?.Cartoes?.find((card) => !card.Virtual && card.Titular)];

export const useHolderPhysicalCards = () => useSelector(getHolderPhysicalCards);

export const useVirtualCardNumber = () =>
  useSelector(
    ({ productsReducer, accountReducer }: AppReducers) =>
      productsReducer?.data?.[0]?.Cartoes?.find(
        (card) =>
          !card?.NrCartao?.endsWith(accountReducer?.card?.cardNumber?.slice(-4) ?? '') &&
          !!card?.Virtual
      )?.NrCartao
  );

export const useAdditionalCards = () => {
  const cards = useSelector(
    ({ productsReducer }: AppReducers) =>
      productsReducer.data.map((products) => products.Cartoes)[0]
  );
  const additionalCards = cards?.filter((card) => !card.Virtual && !card.Titular);
  return additionalCards;
};

export const useAdditionalCardsEnabled = () => {
  const cards = useSelector(
    ({ productsReducer }: AppReducers) =>
      productsReducer.data.map((products) => products.Cartoes)[0]
  );
  const additionalCardsEnabled = cards?.filter(
    (card) =>
      !card.Virtual &&
      !card.Titular &&
      !getIsCanceledCard({
        cancellationReason: card.MotivoCancelamento,
        blockType: card.TipoBloqueio,
      })
  );
  const count = additionalCardsEnabled?.length || 0;
  return {
    additionalCardsEnabled,
    count,
    hasReachedMaxAdditionalCards: count >= 9,
  };
};

export const useIsAdditionalCard = (cardNumber?: string) => {
  const isAdditionalCard = useSelector(({ productsReducer }: AppReducers) => {
    if (!cardNumber) return false;
    return productsReducer.data
      .map((products) => products.Cartoes)?.[0]
      ?.some((card) => card.NrCartao.slice(-4) === cardNumber.slice(-4) && !card.Titular);
  });
  return isAdditionalCard;
};

export const usePendingCards = () => {
  const cards = useSelector(({ productsReducer }: AppReducers) =>
    productsReducer?.data?.[0]?.Cartoes?.filter(
      (card) => !card.Virtual && card.TipoBloqueio === 'XW' && card.MotivoCancelamento === '900'
    )
  );
  return cards;
};

export const useIsTypeProduct = () =>
  useSelector(({ productsReducer }: AppReducers) => {
    const logo = productsReducer.data[0]?.Logo?.toString();

    if (!logo) {
      return 'cardBasic';
    }

    const CARD_TYPES = {
      light: ['461'],
      premium: ['761', '420', '701', '429'],
    };

    if (CARD_TYPES.light.includes(logo)) {
      return 'cardLight';
    }

    if (CARD_TYPES.premium.includes(logo)) {
      return 'cardPremium';
    }

    return 'cardBasic';
  });

export const getSelectedCard = ({
  productsReducer,
  numberCard,
}: {
  productsReducer: ProductsReducerProps;
  numberCard?: string;
}) => {
  const cards = productsReducer.data.map((products) => products.Cartoes)[0];
  if (!numberCard) return null;
  const selectedCard = cards?.find((card) => card.NrCartao.endsWith(numberCard.slice(-4)));
  if (selectedCard) {
    return selectedCard;
  }
  return null;
};

export const useSelectedCard = (numberCard?: string) => {
  const reducer = useSelector(({ productsReducer }: AppReducers) => productsReducer);
  const selectedCard = getSelectedCard({
    productsReducer: reducer,
    numberCard,
  });
  return selectedCard;
};
export const useIsUserAmex = () =>
  useSelector(({ productsReducer }: { productsReducer: ProductsReducerProps }) =>
    ['760', '761', '762', '701'].includes(productsReducer?.data?.[0]?.Logo?.toString() || '')
  );

export const getClientNRC = () => {
  return useSelector(({ customerReducer }: AppReducers) => customerReducer.id);
}

